mapper.select:
SELECT *
FROM recommendation_record
WHERE id = #{id}
  AND user_id = #{userId}
LIMIT 1

SELECT

FROM recommendation_record r
WHERE r.id = #{id}
  AND r.user_id = #{userId}
LIMIT 1

SELECT
FROM recommendation_record r
ORDER BY r.created_at DESC, r.id DESC LIMIT #{query.pageSize} OFFSET #{query.offset}

SELECT MAX(created_at)
FROM recommendation_record
WHERE user_id = #{userId}

    AND rec_type = #{recType}

SELECT

FROM recommendation_record r
WHERE r.user_id = #{userId}
  AND r.created_at = #{latestTime}

    AND r.rec_type = #{recType}

ORDER BY r.id DESC

SELECT
FROM recommendation_record r LEFT JOIN sys_user u ON r.user_id = u.id
ORDER BY r.created_at DESC, r.id DESC LIMIT #{query.pageSize} OFFSET #{query.offset}

SELECT target_id
FROM recommendation_record
WHERE user_id = #{userId}

      AND rec_type = #{recType}

ORDER BY created_at DESC, id DESC
LIMIT #{limit}
